tasks.description:
Create unit tests for the new `useExternalAdapterCatalog` hook to serve as the primary regression guard for the Claude Code bug.

## File to Create

### `apps/client/src/layers/entities/relay/model/__tests__/use-external-adapter-catalog.test.ts` (new)

Three tests, each with a clear purpose:

```ts
// @vitest-environment jsdom
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook } from '@testing-library/react';
import '@testing-library/jest-dom/vitest';
import type { CatalogEntry } from '@dorkos/shared/relay-schemas';

// Mock the underlying useAdapterCatalog hook
const mockUseAdapterCatalog = vi.fn<() => { data: CatalogEntry[] | undefined }>(() => ({
  data: undefined,
}));

vi.mock('../use-adapter-catalog', () => ({
  useAdapterCatalog: (...args: unknown[]) => mockUseAdapterCatalog(...args),
}));

import { useExternalAdapterCatalog, ADAPTER_CATEGORY_INTERNAL } from '../use-external-adapter-catalog';

// --- Test fixtures ---

function makeCatalogEntry(overrides: {
  type?: string;
  category?: string;
  instanceId?: string;
  displayName?: string;
}): CatalogEntry {
  const type = overrides.type ?? 'telegram';
  const id = overrides.instanceId ?? `${type}-1`;
  return {
    manifest: {
      type,
      displayName: overrides.displayName ?? 'Telegram',
      description: 'Test adapter',
      category: (overrides.category ?? 'messaging') as CatalogEntry['manifest']['category'],
      builtin: true,
      configFields: [],
      multiInstance: false,
    },
    instances: [
      {
        id,
        enabled: true,
        status: {
          id,
          type,
          displayName: overrides.displayName ?? 'Telegram',
          state: 'connected',
          messageCount: { inbound: 0, outbound: 0 },
          errorCount: 0,
        },
      },
    ],
  };
}

describe('useExternalAdapterCatalog', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  /**
   * Verifies the hook strips `category: 'internal'` entries from the catalog.
   * This test is the primary regression guard for the Claude Code bug —
   * if anyone removes or weakens the filter, it will fail.
   */
  it('filters out adapters with category: internal', () => {
    const internalEntry = makeCatalogEntry({
      type: 'claude-code',
      category: 'internal',
      instanceId: 'claude-code-1',
      displayName: 'Claude Code',
    });
    const externalEntry = makeCatalogEntry({
      type: 'telegram',
      category: 'messaging',
      instanceId: 'telegram-1',
      displayName: 'Telegram',
    });

    mockUseAdapterCatalog.mockReturnValue({
      data: [internalEntry, externalEntry],
    });

    const { result } = renderHook(() => useExternalAdapterCatalog());

    expect(result.current.data).toHaveLength(1);
    expect(result.current.data[0].manifest.type).toBe('telegram');
    expect(result.current.data.some((e) => e.manifest.category === 'internal')).toBe(false);
  });

  /**
   * Verifies that `data` keeps a stable reference when the underlying query
   * data does not change. This guards against re-render storms if a consumer
   * passes `data` into a `useEffect` dep list or a child component prop.
   */
  it('returns a stable data reference when query data is unchanged', () => {
    const catalogData = [makeCatalogEntry({ type: 'telegram', category: 'messaging' })];
    mockUseAdapterCatalog.mockReturnValue({ data: catalogData });

    const { result, rerender } = renderHook(() => useExternalAdapterCatalog());
    const firstData = result.current.data;

    rerender();
    const secondData = result.current.data;

    expect(firstData).toBe(secondData); // Same reference, not just equal
  });

  /**
   * Verifies that when the Relay feature is disabled, the hook returns an
   * empty catalog and does not trigger a network request. This guards the
   * "Relay off" code path that ChannelsTab relies on for its empty state.
   */
  it('returns empty data when disabled', () => {
    mockUseAdapterCatalog.mockReturnValue({ data: undefined });

    const { result } = renderHook(() => useExternalAdapterCatalog(false));

    expect(result.current.data).toEqual([]);
    expect(mockUseAdapterCatalog).toHaveBeenCalledWith(false);
  });

  it('exports the ADAPTER_CATEGORY_INTERNAL constant as "internal"', () => {
    expect(ADAPTER_CATEGORY_INTERNAL).toBe('internal');
  });
});
```

## Implementation Steps

1. Create the `__tests__` directory if it does not exist: `apps/client/src/layers/entities/relay/model/__tests__/` (it already exists with other test files).
2. Create `use-external-adapter-catalog.test.ts` with the content above.
3. Run `pnpm vitest run apps/client/src/layers/entities/relay/model/__tests__/use-external-adapter-catalog.test.ts` and confirm all 4 tests pass.

## Acceptance Criteria

- [ ] Test file exists at the specified path
- [ ] 4 tests pass: filter test, stability test, disabled test, constant export test
- [ ] The filter test explicitly includes a `category: 'internal'` entry and asserts it is excluded
- [ ] The stability test uses `toBe` (reference equality), not `toEqual`
- [ ] The disabled test passes `false` to the hook and asserts `data` is `[]`
- [ ] No test uses arbitrary timeouts or `waitFor` without assertions

