## File to Modify

### `apps/client/src/layers/features/agent-settings/ui/ChannelPicker.tsx`

Replace the entire file content. The current file imports `useAdapterCatalog` and `useRelayEnabled` directly and has an `onSetupNewChannel` prop that triggers cross-dialog navigation. The new version receives filtered catalog data as a prop and provides an `onRequestSetup` callback.

**New component signature:**

```tsx
import { useState, useMemo } from 'react';
import { Plus } from 'lucide-react';
import { Popover, PopoverContent, PopoverTrigger, Button } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import type { AdapterManifest, AdapterStatus, CatalogEntry } from '@dorkos/shared/relay-schemas';

interface ChannelPickerProps {
  /** Pre-filtered external adapter catalog (no `category: 'internal'` entries). */
  catalog: CatalogEntry[];
  /** Adapter IDs already bound to this agent (shown as "connected" in the picker). */
  boundAdapterIds: Set<string>;
  /** Called when the user selects an existing adapter instance to bind. */
  onSelectChannel: (adapterId: string) => void;
  /** Called when the user picks an adapter type to configure from scratch. */
  onRequestSetup: (manifest: AdapterManifest) => void;
  /** Whether the popover trigger button is disabled. */
  disabled?: boolean;
}
```

**Key changes from current implementation:**

1. Remove `useAdapterCatalog` and `useRelayEnabled` imports from `@/layers/entities/relay`.
2. Remove `onSetupNewChannel` prop, replace with `onRequestSetup(manifest: AdapterManifest)`.
3. Add `catalog: CatalogEntry[]` prop (pre-filtered, from parent).
4. Build `configuredChannels` from `catalog` prop instead of internal hook data.
5. Compute `availableToSetup` list: catalog entries where `!entry.manifest.deprecated && (entry.instances.length === 0 || entry.manifest.multiInstance)`. These are adapter types that can be set up fresh.
6. Replace the footer "Set up a new channel..." button with an "Available to set up" section inside the popover, separated by a `border-t` divider.
7. When both configured channels and available-to-setup lists are empty, show "No channels available" message.

**Popover structure:**

```
┌─ Connect to Channel ─────────────────┐
│ [CONFIGURED]                     │
│ ● Telegram — Dev chat  connected │
│ ● Telegram — Support   connected │
│ ● Slack — #general     error     │
│                                  │
│ ── Available to set up ────────  │
│ + Webhook                         │
│ + Telegram (new instance)         │
└──────────────────────────────────┘
```

**Full new component implementation:**

```tsx
import { useState, useMemo } from 'react';
import { Plus } from 'lucide-react';
import { Popover, PopoverContent, PopoverTrigger, Button } from '@/layers/shared/ui';
import { cn } from '@/layers/shared/lib';
import type { AdapterManifest, AdapterStatus, CatalogEntry } from '@dorkos/shared/relay-schemas';

interface ChannelPickerProps {
  /** Pre-filtered external adapter catalog (no `category: 'internal'` entries). */
  catalog: CatalogEntry[];
  /** Adapter IDs already bound to this agent (shown as "connected" in the picker). */
  boundAdapterIds: Set<string>;
  /** Called when the user selects an existing adapter instance to bind. */
  onSelectChannel: (adapterId: string) => void;
  /** Called when the user picks an adapter type to configure from scratch. */
  onRequestSetup: (manifest: AdapterManifest) => void;
  /** Whether the popover trigger button is disabled. */
  disabled?: boolean;
}

interface ChannelItem {
  id: string;
  displayName: string;
  label: string | undefined;
  state: AdapterStatus['state'];
  isDisabled: boolean;
  alreadyBound: boolean;
}

const STATE_DOT_CLASS: Record<AdapterStatus['state'], string> = {
  connected: 'bg-green-500',
  disconnected: 'bg-amber-500',
  error: 'bg-red-500',
  starting: 'bg-amber-400',
  stopping: 'bg-amber-400',
  reconnecting: 'bg-amber-400',
};

/**
 * Popover listing all configured relay channel instances for binding to an agent,
 * plus unconfigured adapter types available to set up.
 *
 * Receives a pre-filtered catalog as a prop (no internal data fetching).
 * Shows a status dot, adapter name, optional label, and connection state for each
 * configured channel. A second section lists adapter types available for fresh setup.
 */
export function ChannelPicker({
  catalog,
  boundAdapterIds,
  onSelectChannel,
  onRequestSetup,
  disabled,
}: ChannelPickerProps) {
  const [open, setOpen] = useState(false);

  const configuredChannels: ChannelItem[] = useMemo(
    () =>
      catalog.flatMap((entry) =>
        entry.instances.map((inst) => ({
          id: inst.id,
          displayName: inst.status.displayName ?? entry.manifest.displayName,
          label: inst.label,
          state: inst.status.state,
          isDisabled: inst.status.state === 'error' || !inst.enabled,
          alreadyBound: boundAdapterIds.has(inst.id),
        }))
      ),
    [catalog, boundAdapterIds]
  );

  const availableToSetup = useMemo(
    () =>
      catalog.filter(
        (entry) =>
          !entry.manifest.deprecated && (entry.instances.length === 0 || entry.manifest.multiInstance)
      ),
    [catalog]
  );

  function handleSelect(adapterId: string) {
    onSelectChannel(adapterId);
    setOpen(false);
  }

  function handleSetup(manifest: AdapterManifest) {
    setOpen(false);
    onRequestSetup(manifest);
  }

  const isEmpty = configuredChannels.length === 0 && availableToSetup.length === 0;

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" disabled={disabled}>
          <Plus className="mr-1.5 size-3.5" />
          Connect to Channel
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-72 p-0" align="start">
        <div className="max-h-64 overflow-y-auto">
          {isEmpty ? (
            <div className="px-3 py-4 text-center">
              <p className="text-muted-foreground text-sm">
                No channels available
              </p>
            </div>
          ) : (
            <>
              {/* Configured instances */}
              {configuredChannels.length > 0 && (
                <div className="py-1">
                  {configuredChannels.map((channel) => (
                    <button
                      key={channel.id}
                      disabled={channel.isDisabled || channel.alreadyBound}
                      onClick={() => handleSelect(channel.id)}
                      className={cn(
                        'flex w-full items-center gap-3 px-3 py-2 text-left text-sm transition-colors',
                        'hover:bg-accent disabled:cursor-not-allowed disabled:opacity-50'
                      )}
                    >
                      <span
                        className={cn('size-2 shrink-0 rounded-full', STATE_DOT_CLASS[channel.state])}
                      />
                      <div className="min-w-0 flex-1">
                        <p className="truncate font-medium">{channel.displayName}</p>
                        {channel.label && (
                          <p className="text-muted-foreground truncate text-xs">{channel.label}</p>
                        )}
                      </div>
                      <span className="text-muted-foreground/60 text-xs">
                        {channel.alreadyBound ? 'connected' : channel.state}
                      </span>
                    </button>
                  ))}
                </div>
              )}

              {/* Available to set up */}
              {availableToSetup.length > 0 && (
                <>
                  <div className="border-t" />
                  <div className="py-1">
                    <p className="text-muted-foreground px-3 py-1 text-xs font-medium">
                      Available to set up
                    </p>
                    {availableToSetup.map((entry) => (
                      <button
                        key={entry.manifest.type}
                        onClick={() => handleSetup(entry.manifest)}
                        className={cn(
                          'flex w-full items-center gap-3 px-3 py-2 text-left text-sm transition-colors',
                          'hover:bg-accent'
                        )}
                      >
                        <Plus className="size-3.5 shrink-0" />
                        <span className="truncate font-medium">{entry.manifest.displayName}</span>
                      </button>
                    ))}
                  </div>
                </>
              )}
            </>
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
}
```

**Removals:**
- `import { useAdapterCatalog, useRelayEnabled } from '@/layers/entities/relay';` (deleted entirely)
- `onSetupNewChannel` prop (replaced by `onRequestSetup`)
- The footer "Set up a new channel..." button (replaced by inline "Available to set up" section)
- The internal `useRelayEnabled()` and `useAdapterCatalog()` hook calls

## Implementation Steps

1. Replace the contents of `apps/client/src/layers/features/agent-settings/ui/ChannelPicker.tsx` with the new implementation above.
2. Run `pnpm typecheck` — this will initially fail because the parent `ChannelsTab.tsx` still passes the old props. That is expected and will be fixed in task 2.3.
3. Verify the new component has no imports from `@/layers/entities/relay`.

## Acceptance Criteria

- [ ] `ChannelPicker` no longer imports from `@/layers/entities/relay`
- [ ] `ChannelPicker` accepts `catalog: CatalogEntry[]` prop
- [ ] `ChannelPicker` accepts `onRequestSetup: (manifest: AdapterManifest) => void` prop
- [ ] The old `onSetupNewChannel` prop is removed
- [ ] The popover has two sections: configured channels + available to set up
- [ ] The "Available to set up" section only shows when qualifying entries exist
- [ ] Empty state shows "No channels available" when both sections are empty
- [ ] `configuredChannels` and `availableToSetup` are computed with `useMemo`
- [ ] The popover closes before calling `onRequestSetup` (same pattern as `handleSelect`)

This is the main bug-fix task. Rewrite the agent-settings `ChannelsTab` to: (1) use the shared `useExternalAdapterCatalog` hook instead of `useAdapterCatalog`, (2) memoize the `adapterStatusByInstanceId` Map, (3) collapse the three `resolve*` helpers into a single `resolveAdapterDisplay`, (4) hoist wizard state and render `AdapterSetupWizard` inline (fixing the context-loss bug), and (5) remove all cross-dialog navigation code.

## File to Modify

### `apps/client/src/layers/features/agent-settings/ui/ChannelsTab.tsx`

Replace the entire file with the new implementation. The current file is 233 lines; the new file will be similar in size.

**Full new component:**

```tsx
import { useState, useCallback, useMemo } from 'react';
import { toast } from 'sonner';
import {
  useBindings,
  useCreateBinding,
  useDeleteBinding,
  useUpdateBinding,
} from '@/layers/entities/binding';
import { useExternalAdapterCatalog, useRelayEnabled } from '@/layers/entities/relay';
import { BindingDialog, type BindingFormValues } from '@/layers/features/mesh/ui/BindingDialog';
import { AdapterSetupWizard } from '@/layers/features/relay';
import type { AgentManifest } from '@dorkos/shared/mesh-schemas';
import type { AdapterBinding, AdapterManifest } from '@dorkos/shared/relay-schemas';
import { ChannelBindingCard } from './ChannelBindingCard';
import { ChannelPicker } from './ChannelPicker';

interface ChannelsTabProps {
  /** The agent whose channel bindings are displayed and managed. */
  agent: AgentManifest;
}

/** Display fields derived from a catalog entry for a bound adapter instance. */
interface AdapterDisplay {
  state: 'connected' | 'disconnected' | 'error';
  name: string;
  errorMessage?: string;
}

interface EditDialogState {
  open: boolean;
  binding: AdapterBinding | null;
  adapterName: string;
}

interface WizardState {
  open: boolean;
  manifest?: AdapterManifest;
}

const CLOSED_EDIT_DIALOG: EditDialogState = { open: false, binding: null, adapterName: '' };
const CLOSED_WIZARD: WizardState = { open: false };

export function ChannelsTab({ agent }: ChannelsTabProps) {
  const relayEnabled = useRelayEnabled();
  const { data: allBindings = [] } = useBindings();
  const { data: externalCatalog = [] } = useExternalAdapterCatalog(relayEnabled);
  const createBinding = useCreateBinding();
  const deleteBinding = useDeleteBinding();
  const updateBinding = useUpdateBinding();

  const [editDialog, setEditDialog] = useState<EditDialogState>(CLOSED_EDIT_DIALOG);
  const [wizardState, setWizardState] = useState<WizardState>(CLOSED_WIZARD);

  const agentBindings = allBindings.filter((b) => b.agentId === agent.id);

  const adapterDisplayByInstanceId = useMemo(() => {
    const map = new Map<string, AdapterDisplay>();
    for (const entry of externalCatalog) {
      for (const inst of entry.instances) {
        const raw = inst.status.state;
        const state: AdapterDisplay['state'] =
          raw === 'connected' || raw === 'error' ? raw : 'disconnected';
        map.set(inst.id, {
          state,
          name: inst.status.displayName ?? entry.manifest.displayName,
          errorMessage: inst.status.lastError ?? undefined,
        });
      }
    }
    return map;
  }, [externalCatalog]);

  const resolveAdapterDisplay = useCallback(
    (adapterId: string): AdapterDisplay =>
      adapterDisplayByInstanceId.get(adapterId) ?? { state: 'disconnected', name: adapterId },
    [adapterDisplayByInstanceId]
  );

  const boundAdapterIds = useMemo(
    () => new Set(agentBindings.map((b) => b.adapterId)),
    [agentBindings]
  );

  const handleSelectChannel = useCallback(
    async (adapterId: string) => {
      try {
        await createBinding.mutateAsync({
          adapterId,
          agentId: agent.id,
          sessionStrategy: 'per-chat',
          label: '',
          canInitiate: false,
          canReply: true,
          canReceive: true,
        });
        toast.success('Channel connected');
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to connect channel');
      }
    },
    [agent.id, createBinding]
  );

  const handleRequestSetup = useCallback((manifest: AdapterManifest) => {
    setWizardState({ open: true, manifest });
  }, []);

  const handleEdit = useCallback(
    (binding: AdapterBinding) => {
      setEditDialog({
        open: true,
        binding,
        adapterName: resolveAdapterDisplay(binding.adapterId).name,
      });
    },
    [resolveAdapterDisplay]
  );

  const handleRemove = useCallback(
    async (bindingId: string) => {
      try {
        await deleteBinding.mutateAsync(bindingId);
        toast.success('Channel removed');
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to remove channel');
      }
    },
    [deleteBinding]
  );

  const handleEditConfirm = useCallback(
    async (values: BindingFormValues) => {
      if (!editDialog.binding) return;
      try {
        await updateBinding.mutateAsync({
          id: editDialog.binding.id,
          updates: {
            sessionStrategy: values.sessionStrategy,
            label: values.label,
            chatId: values.chatId,
            channelType: values.channelType,
            canInitiate: values.canInitiate,
            canReply: values.canReply,
            canReceive: values.canReceive,
          },
        });
        toast.success('Binding updated');
        setEditDialog(CLOSED_EDIT_DIALOG);
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to update binding');
      }
    },
    [editDialog.binding, updateBinding]
  );

  const handleEditDelete = useCallback(
    async (bindingId: string) => {
      try {
        await deleteBinding.mutateAsync(bindingId);
        toast.success('Channel removed');
        setEditDialog(CLOSED_EDIT_DIALOG);
      } catch (err) {
        toast.error(err instanceof Error ? err.message : 'Failed to remove channel');
      }
    },
    [deleteBinding]
  );

  return (
    <div className="space-y-4">
      {/* Binding list */}
      {agentBindings.length > 0 ? (
        <div className="space-y-2">
          {agentBindings.map((binding) => {
            const display = resolveAdapterDisplay(binding.adapterId);
            return (
              <ChannelBindingCard
                key={binding.id}
                binding={binding}
                channelName={display.name}
                adapterState={display.state}
                errorMessage={display.errorMessage}
                onEdit={() => handleEdit(binding)}
                onRemove={() => handleRemove(binding.id)}
              />
            );
          })}
        </div>
      ) : (
        <p className="text-muted-foreground py-2 text-sm">
          {relayEnabled ? 'No channels connected.' : 'Relay is not enabled.'}
        </p>
      )}

      {/* Add channel picker */}
      <ChannelPicker
        catalog={externalCatalog}
        boundAdapterIds={boundAdapterIds}
        onSelectChannel={handleSelectChannel}
        onRequestSetup={handleRequestSetup}
        disabled={!relayEnabled || createBinding.isPending}
      />

      {/* Edit binding dialog */}
      {editDialog.binding && (
        <BindingDialog
          open={editDialog.open}
          onOpenChange={(open) => {
            if (!open) setEditDialog(CLOSED_EDIT_DIALOG);
          }}
          mode="edit"
          initialValues={{
            adapterId: editDialog.binding.adapterId,
            agentId: editDialog.binding.agentId,
            sessionStrategy: editDialog.binding.sessionStrategy,
            label: editDialog.binding.label,
            chatId: editDialog.binding.chatId,
            channelType: editDialog.binding.channelType,
            canInitiate: editDialog.binding.canInitiate,
            canReply: editDialog.binding.canReply,
            canReceive: editDialog.binding.canReceive,
          }}
          adapterName={editDialog.adapterName}
          agentName={agent.name}
          bindingId={editDialog.binding.id}
          onConfirm={handleEditConfirm}
          onDelete={handleEditDelete}
          isPending={updateBinding.isPending || deleteBinding.isPending}
        />
      )}

      {/* Inline setup wizard — opens on top of the AgentDialog */}
      {wizardState.manifest && (
        <AdapterSetupWizard
          open={wizardState.open}
          onOpenChange={(open) => {
            if (!open) setWizardState(CLOSED_WIZARD);
          }}
          manifest={wizardState.manifest}
          existingAdapterIds={externalCatalog.flatMap((e) => e.instances.map((i) => i.id))}
        />
      )}
    </div>
